import{_ as t,c as r,o,ag as c}from"./chunks/framework.CSeR4K32.js";const k=JSON.parse('{"title":"前言","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/guide/docker/docker_precheck.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"一键虚拟化项目"}],["meta",{"property":"og:locale","content":"zh_CN"}],["meta",{"property":"og:title","content":"前言"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/guide/docker/docker_precheck.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"前言"}]]},"headers":[],"relativePath":"guide/docker/docker_precheck.md","filePath":"guide/docker/docker_precheck.md","lastUpdated":1782003947000}'),a={name:"guide/docker/docker_precheck.md"};function p(d,e,i,n,l,s){return o(),r("div",null,e[0]||(e[0]=[c('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><p>以下为非自定义部分的介绍，自定义部分有独立说明，请勿混淆。</p><p>如果宿主机没有 IPv6 子网但你希望给容器分配 IPv6 地址，可先参考 <code>Incus</code> 或 <code>LXD</code> 模块中 <code>自定义</code> 分区的 <code>给宿主机附加免费的IPv6地址段</code>，先给宿主机附加 IPv6 子网后再进行环境安装。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果宿主机带 IPv6 网络，安装过程可能改变宿主机网络结构。请确保宿主机可随时重装系统，且运行前无重要数据。</p></div><p>欢迎给项目一个<code>Star</code>进行免费的支持--&gt;<a href="https://github.com/oneclickvirt/docker" target="_blank" rel="noreferrer">https://github.com/oneclickvirt/docker</a></p><h2 id="项目特点" tabindex="-1">项目特点 <a class="header-anchor" href="#项目特点" aria-label="Permalink to &quot;项目特点&quot;">​</a></h2><p>通过docker批量或单独开设NAT服务器(Bulk or individual NAT server provisioning via docker)</p><p>默认使用debian系统可选alpine系统，每个容器自带1个外网ssh端口，25个内外网一致端口，可选择是否绑定IPV6地址</p><p>默认创建的是非特权容器，且不挂载与宿主机的docker的守护进程之间的通信，所以<strong>宿主机创建的docker虚拟化的NAT服务器内无法再嵌套虚拟化docker</strong></p><p>默认安装并启用lxcfs，使得在容器内的查询资源时CPU和内存使用的是配置的视图而不是宿主机的视图</p><p>默认可选择是否共享宿主机的硬盘，在Docker安装的时候可选择是否安装为可限制硬盘大小的环境</p><h2 id="配置要求" tabindex="-1">配置要求 <a class="header-anchor" href="#配置要求" aria-label="Permalink to &quot;配置要求&quot;">​</a></h2><p>系统可安装 Docker 即可使用；网络可访问 GitHub Raw 页面即可；建议至少保留 3G 空闲硬盘。</p><p>(如果需要绑定IPV6地址，那么请保证使用本套脚本的环境预设脚本进行环境安装，需要它自动预设部分设置)</p><p>如果硬件资源只是好了一点，需要限制更多东西并需要限制硬盘大小，可使用incus分区的脚本批量开LXC虚拟化的容器</p><p>如果硬件非常好资源很多，可使用PVE分区的脚本批量开KVM虚拟化的虚拟机</p><p>推荐在开设NAT服务器前先增加部分SWAP虚拟内存，避免突发的内存占用导致宿主机卡死</p>',17)]))}const _=t(a,[["render",p]]);export{k as __pageData,_ as default};
